import React, { useState } from 'react';
import { Menu, X } from 'lucide-react';

const Navbar = () => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  const navLinks = [
    { name: 'Features', href: '#' },
    { name: 'Solutions', href: '#' },
    { name: 'Pricing', href: '#' },
    { name: 'Resources', href: '#' },
  ];

  return (
    <nav className="relative bg-gray-950 font-dm-sans text-white py-4 md:py-6">
      <div className="container mx-auto px-4 sm:px-6 lg:px-8 flex justify-between items-center">
        {/* Brand Logo and Name */}
        <a href="#" className="flex items-center space-x-2 text-2xl font-bold text-gray-100 hover:text-zinc-300 transition-colors duration-300">
          <span className="text-zinc-400">Aether</span>Link
        </a>

        {/* Desktop Navigation Links */}
        <div className="hidden md:flex space-x-8 lg:space-x-10 items-center">
          {navLinks.map((link) => (
            <a
              key={link.name}
              href={link.href}
              className="text-lg text-gray-200 hover:text-zinc-300 transition-colors duration-300 relative group"
            >
              {link.name}
              <span className="absolute bottom-0 left-0 w-0 h-0.5 bg-zinc-400 group-hover:w-full transition-all duration-300"></span>
            </a>
          ))}
        </div>

        {/* Desktop Action Button */}
        <div className="hidden md:block">
          <button className="bg-zinc-600 text-white px-6 py-2 rounded-md text-lg font-medium hover:bg-zinc-700 transition-colors duration-300 focus:outline-none focus:ring-2 focus:ring-zinc-500 focus:ring-opacity-50">
            Sign Up
          </button>
        </div>

        {/* Mobile Menu Button */}
        <div className="md:hidden flex items-center">
          <button
            onClick={() => setIsMenuOpen(!isMenuOpen)}
            className="text-gray-200 hover:text-zinc-300 focus:outline-none focus:ring-2 focus:ring-zinc-500 focus:ring-opacity-50 rounded-md p-1"
            aria-label="Toggle menu"
          >
            {isMenuOpen ? <X size={28} /> : <Menu size={28} />}
          </button>
        </div>
      </div>

      {/* Mobile Menu Overlay */}
      <div
        className={`md:hidden absolute top-full left-0 w-full bg-gray-900 shadow-lg z-50 overflow-hidden transition-all duration-300 ease-in-out ${
          isMenuOpen ? 'max-h-screen opacity-100' : 'max-h-0 opacity-0'
        }`}
      >
        <div className="flex flex-col items-start px-4 sm:px-6 py-4 space-y-4">
          {navLinks.map((link) => (
            <a
              key={link.name}
              href={link.href}
              className="block text-xl text-gray-200 hover:text-zinc-300 transition-colors duration-300 w-full py-2"
              onClick={() => setIsMenuOpen(false)}
            >
              {link.name}
            </a>
          ))}
          <button className="bg-zinc-600 text-white px-6 py-3 rounded-md text-xl font-medium hover:bg-zinc-700 transition-colors duration-300 w-full focus:outline-none focus:ring-2 focus:ring-zinc-500 focus:ring-opacity-50 mt-4">
            Sign Up
          </button>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;

