import React, { useState } from 'react';
import { ChevronLeft, ChevronRight, Quote } from 'lucide-react';

const TestimonialCarousel = () => {
  const testimonials = [
    {
      id: 1,
      quote: "AetherLink has revolutionized our team's productivity. The seamless collaboration tools and intuitive interface are a game-changer for our daily operations.",
      name: "Sarah Chen",
      title: "CTO, Innovate Solutions",
      avatar: "https://randomuser.me/api/portraits/women/1.jpg",
    },
    {
      id: 2,
      quote: "We've seen a significant improvement in our project delivery times since adopting AetherLink. It's truly an all-in-one platform that adapts to our needs.",
      name: "Michael Lee",
      title: "Project Manager, GlobalTech Inc.",
      avatar: "https://randomuser.me/api/portraits/men/2.jpg",
    },
    {
      id: 3,
      quote: "The best part about AetherLink is how it simplifies complex workflows. Our team is more connected and efficient than ever before, leading to better outcomes.",
      name: "Emily White",
      title: "Lead Developer, Synergy Corp.",
      avatar: "https://randomuser.me/api/portraits/women/3.jpg",
    },
    {
      id: 4,
      quote: "From initial concept to final deployment, AetherLink has been an indispensable tool. Highly recommended for any growing business looking for an edge.",
      name: "David Kim",
      title: "CEO, Visionary Startups",
      avatar: "https://randomuser.me/api/portraits/men/4.jpg",
    },
  ];

  const [currentIndex, setCurrentIndex] = useState(0);

  const goToNext = () => {
    setCurrentIndex((prevIndex) => (prevIndex + 1) % testimonials.length);
  };

  const goToPrevious = () => {
    setCurrentIndex((prevIndex) => (prevIndex - 1 + testimonials.length) % testimonials.length);
  };

  const goToSlide = (index) => {
    setCurrentIndex(index);
  };

  const currentTestimonial = testimonials[currentIndex];

  return (
    <section className="bg-zinc-950 font-['DM_Sans'] text-zinc-200 py-24 sm:py-32">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="text-center">
          <h2 className="text-3xl sm:text-4xl font-bold text-zinc-50 tracking-tight">
            What Our Users Say
          </h2>
          <p className="mt-4 text-lg text-zinc-400 max-w-2xl mx-auto">
            Hear from the professionals who are transforming their workflows with AetherLink.
          </p>
        </div>

        <div className="relative mt-16 max-w-3xl mx-auto">
          {/* Testimonial Card */}
          <div className="bg-zinc-900 p-8 sm:p-12 rounded-md flex flex-col items-center text-center shadow-none border-none">
            <Quote className="w-12 h-12 text-zinc-600 mb-6" />
            <p className="text-xl sm:text-2xl italic text-zinc-100 leading-relaxed">
              &ldquo;{currentTestimonial.quote}&rdquo;
            </p>
            <div className="mt-8 pt-6 border-t border-zinc-800 flex flex-col sm:flex-row items-center justify-center sm:space-x-4">
              <img
                src={currentTestimonial.avatar}
                alt={currentTestimonial.name}
                className="w-14 h-14 rounded-full ring-2 ring-zinc-700 object-cover mb-4 sm:mb-0"
              />
              <div>
                <p className="font-semibold text-lg text-zinc-50">{currentTestimonial.name}</p>
                <p className="text-zinc-400 text-sm">{currentTestimonial.title}</p>
              </div>
            </div>
          </div>

          {/* Navigation Buttons */}
          <button
            onClick={goToPrevious}
            className="absolute left-0 top-1/2 -translate-x-1/2 -translate-y-1/2 p-3 rounded-full bg-zinc-800 text-zinc-300 hover:bg-zinc-700 hover:text-zinc-50 transition-colors focus:outline-none focus:ring-2 focus:ring-zinc-600"
            aria-label="Previous testimonial"
          >
            <ChevronLeft className="w-6 h-6" />
          </button>
          <button
            onClick={goToNext}
            className="absolute right-0 top-1/2 translate-x-1/2 -translate-y-1/2 p-3 rounded-full bg-zinc-800 text-zinc-300 hover:bg-zinc-700 hover:text-zinc-50 transition-colors focus:outline-none focus:ring-2 focus:ring-zinc-600"
            aria-label="Next testimonial"
          >
            <ChevronRight className="w-6 h-6" />
          </button>
        </div>

        {/* Pagination Dots */}
        <div className="flex justify-center mt-12 space-x-2">
          {testimonials.map((_, index) => (
            <button
              key={index}
              onClick={() => goToSlide(index)}
              className={`block w-3 h-3 rounded-full transition-colors duration-300 ${
                index === currentIndex ? 'bg-zinc-600' : 'bg-zinc-800 hover:bg-zinc-700'
              }`}
              aria-label={`Go to testimonial ${index + 1}`}
            ></button>
          ))}
        </div>
      </div>
    </section>
  );
};

export default TestimonialCarousel;

